using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using Microsoft.Extensions.FileProviders;
using System.IO;

public class FileController : Controller
{
    private readonly IFileProvider _fileProvider;

    public FileController(IFileProvider fileProvider)
    {
        _fileProvider = fileProvider;
    }

    [HttpGet("uploads/{*filename}")]
    public IActionResult GetFile(string filename)
    {
        var fileInfo = _fileProvider.GetFileInfo("uploads/" + filename);
        if (!fileInfo.Exists)
        {
            return NotFound();
        }

        var fileExtension = Path.GetExtension(filename);
        new FileExtensionContentTypeProvider().TryGetContentType(fileExtension, out string contentType);

        return PhysicalFile(fileInfo.PhysicalPath, contentType ?? "application/octet-stream");
    }
}